parameters.jsCode:
const items = $input.all();
const productData = $node['Extract Product Data'].json;
const timestamp = new Date().toISOString();
const batchId = `creative_${timestamp.split('T')[0].replace(/-/g, '')}_${Math.random().toString(36).substr(2, 6)}`;

const tiktokScripts = [];
const metaScripts = [];

for (const item of items) {
  if (!item.json.choices) continue;
  const content = item.json.choices[0].message.content;

  try {
    const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleaned);

    if (parsed.creative_id) {
      if (parsed.creative_id.includes('tiktok')) {
        tiktokScripts.push(parsed);
      } else if (parsed.creative_id.includes('meta')) {
        metaScripts.push(parsed);
      }
    }
  } catch (e) {
    console.log('Parse error:', e.message);
  }
}

const finalOutput = {
  creative_batch_id: batchId,
  timestamp: timestamp,
  product_id: productData.product_name.toLowerCase().replace(/\s+/g, '_'),
  product_name: productData.product_name,
  tiktok_creatives: tiktokScripts,
  meta_ads_creatives: metaScripts,
  image_prompts: {
    midjourney_prompts: [
      {
        purpose: 'TikTok thumbnail - messy before',
        prompt: `Chaotic messy ${productData.category} with clutter. Bright natural lighting. iPhone style. --ar 9:16 --style raw --v 6`
      },
      {
        purpose: 'TikTok thumbnail - clean after',
        prompt: `Perfectly clean ${productData.category}. Sparkling surfaces. --ar 9:16 --style raw --v 6`
      },
      {
        purpose: 'Meta Ads hero image',
        prompt: `Product photo of ${productData.product_name} on white marble. Split: messy left, clean right. 5 stars. ${productData.discount_percent}% OFF banner. --ar 1:1 --style raw --v 6`
      }
    ]
  },
  performance_predictions: {
    tiktok: {
      estimated_views: '50K-200K',
      estimated_engagement_rate: '6-8%',
      viral_potential_score: 8.5,
      best_creative: tiktokScripts[0]?.creative_id || 'tiktok_001'
    },
    meta_ads: {
      estimated_ctr: '2.5-4%',
      estimated_cpc: '$0.40-$0.80',
      estimated_roas: '3.5-5x',
      best_creative: metaScripts[0]?.creative_id || 'meta_001'
    }
  },
  next_steps: [
    'Review and approve scripts',
    'Film content or generate via AI',
    'Edit videos with production notes',
    'A/B test TikTok creatives organically',
    'Launch top performer as paid ad'
  ],
  metadata: {
    generated_by: 'TARS Creative Agent v1',
    brand: 'House Charm',
    workflow_version: '1.0'
  }
};

return { json: finalOutput };
